pub async fn get_user_by_id(pool: &sqlx::PgPool, id: &uuid::Uuid) -> Result<GetUserByIdRow, sqlx::Error> {
    sqlx::query_as!(GetUserByIdRow, "SELECT id, name FROM users WHERE id = $1", id)
        .fetch_one(pool)
        .await
}

